use core::ptr::write_volatile;
const LED_PIN: u32 = 0x50020C14;
const SET_BIT: u8 = 0b0000_0001;

pub fn toggle_led() {
    unsafe { write_volatile(LED_PIN as *mut u32, SET_BIT as u32); }
}
```
